import React, { useState, useEffect, useCallback } from "react";
import { Check, TrendingUp, RotateCcw, ChevronLeft, ChevronRight, Beaker, X, Plus, AlertTriangle, Trash2, Package, Sparkles, Settings, Apple, Clock } from "lucide-react";

const LOGO_SRC = "data:image/png;base64,";

const DAY_NAMES = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];

const PRESETS = [
  { name:"Testosterone E", category:"Daily", vialMg:200, bacMl:1, unit:"mg", doseAmount:71, days:[0,1,2,3,4,5,6] },
  { name:"CJC-1295", category:"Peptide", vialMg:2, bacMl:1, unit:"mg", doseAmount:0.25, days:[0,1,2,3,4] },
  { name:"Ipamorelin", category:"Peptide", vialMg:2, bacMl:1, unit:"mg", doseAmount:0.25, days:[0,1,2,3,4] },
  { name:"GHK-Cu", category:"Peptide", vialMg:50, bacMl:3, unit:"mg", doseAmount:2, days:[0,1,2,3,4] },
  { name:"HCG", category:"Support", vialMg:5000, bacMl:1, unit:"IU", doseAmount:250, days:[0,3] },
  { name:"Retatrutide", category:"GLP-1", vialMg:4, bacMl:1, unit:"mg", doseAmount:1.5, days:[3] },
  { name:"BPC-157", category:"Peptide", vialMg:5, bacMl:2, unit:"mg", doseAmount:0.25, days:[0,1,2,3,4,5,6] },
  { name:"TB-500", category:"Peptide", vialMg:5, bacMl:1, unit:"mg", doseAmount:2, days:[0,3] },
  { name:"IGF-1 LR3", category:"Peptide", vialMg:0.2, bacMl:0.5, unit:"mg", doseAmount:0.04, days:[0,1,2,3,4,5,6] },
  { name:"Tirzepatide", category:"GLP-1", vialMg:10, bacMl:2, unit:"mg", doseAmount:2.5, days:[3] },
  { name:"Semaglutide", category:"GLP-1", vialMg:5, bacMl:2, unit:"mg", doseAmount:0.25, days:[3] },
  { name:"Epitalon", category:"Peptide", vialMg:20, bacMl:2, unit:"mg", doseAmount:2, days:[0,1,2,3,4,5,6] }
];

const MACRO_PRESETS = {
  muscle: { name:"Muscle Gain", protein:35, carbs:45, fat:20, icon:"\ud83d\udcaa" },
  fatLoss: { name:"Fat Loss", protein:40, carbs:30, fat:30, icon:"\ud83d\udd25" },
  maintenance: { name:"Maintenance", protein:30, carbs:40, fat:30, icon:"\u2696\ufe0f" }
};

const calcUnits = (doseAmount, p) => (doseAmount / (p.vialMg / p.bacMl)) * 100;
const dosesPerVial = (p) => p.doseAmount > 0 ? Math.floor(p.vialMg / p.doseAmount) : 0;

const getDateKey = (d) => {
  const y = d.getFullYear();
  const m = String(d.getMonth()+1).padStart(2,"0");
  const dy = String(d.getDate()).padStart(2,"0");
  return y + "-" + m + "-" + dy;
};

const formatDate = (d) => d.toLocaleDateString("en-US",{weekday:"long",month:"short",day:"numeric"});

const categoryDot = { Daily:"bg-blue-500", Peptide:"bg-purple-500", Support:"bg-amber-500", "GLP-1":"bg-emerald-500", Custom:"bg-pink-500" };
const CATS = ["Daily","Peptide","Support","GLP-1","Custom"];

function Modal({children, onClose, title}){
  return (
    <div className="fixed inset-0 bg-black/50 flex items-end sm:items-center justify-center p-4 z-50" onClick={onClose}>
      <div className="bg-white rounded-2xl w-full max-w-md p-5 shadow-xl max-h-[85vh] overflow-y-auto" onClick={function(e){e.stopPropagation();}}>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-bold text-slate-900">{title}</h2>
          <button onClick={onClose} className="p-1 hover:bg-slate-100 rounded-lg"><X className="w-5 h-5 text-slate-500"/></button>
        </div>
        {children}
      </div>
    </div>
  );
}

function PresetPicker({onPick, onClose, existingNames}){
  return (
    <Modal onClose={onClose} title="Add from presets">
      <p className="text-sm text-slate-500 mb-3">Tap to add. Edit details after.</p>
      <div className="space-y-2">
        {PRESETS.map(function(p,i){
          var exists = existingNames.includes(p.name.toLowerCase());
          return (
            <button key={i} disabled={exists} onClick={function(){onPick(p);}} className={"w-full text-left p-3 rounded-lg border-2 transition " + (exists ? "bg-slate-50 border-slate-200 opacity-50 cursor-not-allowed" : "bg-white border-slate-200 hover:border-blue-400 active:scale-[0.99]")}>
              <div className="flex items-center gap-2">
                <div className={"w-2 h-2 rounded-full " + (categoryDot[p.category] || "")}/>
                <div className="font-semibold text-slate-900">{p.name}</div>
                {exists && <span className="text-xs text-slate-400 ml-auto">added</span>}
              </div>
              <div className="text-xs text-slate-500 mt-1">{p.doseAmount}{p.unit} \u00b7 {p.days.length===7 ? "Daily" : p.days.map(function(d){return DAY_NAMES[d];}).join(", ")}</div>
            </button>
          );
        })}
      </div>
    </Modal>
  );
}

function PeptideEditor({peptide, vialData, onSave, onClose, onDelete, onNewVial, onSetExpiry}){
  var isNew = !peptide;
  var [form, setForm] = useState(peptide || {
    id: "p_" + Date.now() + "_" + Math.random().toString(36).slice(2,7),
    name:"", category:"Custom", vialMg:5, bacMl:2, unit:"mg", doseAmount:0.25, doseLabel:"", days:[]
  });

  var update = function(k,v){ setForm(function(f){ return Object.assign({},f,{[k]:v}); }); };
  var updateNum = function(k,v){ setForm(function(f){ return Object.assign({},f,{[k]:parseFloat(v)||0}); }); };
  var toggleDay = function(d){ setForm(function(f){
    var newDays = f.days.includes(d) ? f.days.filter(function(x){return x!==d;}) : f.days.concat(d).sort();
    return Object.assign({},f,{days:newDays});
  }); };

  var handleSave = function(){
    if(!form.name.trim()){alert("Name required");return;}
    if(form.days.length===0){alert("Select at least one day");return;}
    onSave(Object.assign({},form,{doseLabel: form.doseAmount + form.unit}));
  };

  var conc = form.bacMl > 0 ? (form.vialMg / form.bacMl).toFixed(4) : "\u2014";
  var units = form.bacMl > 0 && form.doseAmount > 0 ? calcUnits(form.doseAmount, form).toFixed(1) : "\u2014";
  var total = dosesPerVial(form);
  var remaining = vialData ? total - (vialData.dosesUsed || 0) : null;

  return (
    <Modal onClose={onClose} title={isNew ? "Add peptide" : "Edit " + peptide.name}>
      <div className="space-y-4">
        <div><label className="text-sm font-medium text-slate-700 block mb-1">Name</label>
        <input type="text" value={form.name} onChange={function(e){update("name",e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500" placeholder="e.g. BPC-157"/></div>

        <div className="grid grid-cols-2 gap-3">
          <div><label className="text-sm font-medium text-slate-700 block mb-1">Category</label>
          <select value={form.category} onChange={function(e){update("category",e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg">
            {CATS.map(function(c){return <option key={c}>{c}</option>;})}
          </select></div>
          <div><label className="text-sm font-medium text-slate-700 block mb-1">Unit</label>
          <select value={form.unit} onChange={function(e){update("unit",e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg">
            <option value="mg">mg</option><option value="IU">IU</option>
          </select></div>
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div><label className="text-sm font-medium text-slate-700 block mb-1">{"Vial size (" + form.unit + ")"}</label>
          <input type="number" step="any" value={form.vialMg} onChange={function(e){updateNum("vialMg",e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg"/></div>
          <div><label className="text-sm font-medium text-slate-700 block mb-1">BAC water (ml)</label>
          <input type="number" step="any" value={form.bacMl} onChange={function(e){updateNum("bacMl",e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg"/></div>
        </div>

        <div><label className="text-sm font-medium text-slate-700 block mb-1">{"Dose per injection (" + form.unit + ")"}</label>
        <input type="number" step="any" value={form.doseAmount} onChange={function(e){updateNum("doseAmount",e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg"/></div>

        <div><label className="text-sm font-medium text-slate-700 block mb-2">Schedule</label>
        <div className="grid grid-cols-7 gap-1">
          {DAY_NAMES.map(function(d,i){
            return <button key={i} onClick={function(){toggleDay(i);}} className={"py-2 rounded-lg text-xs font-semibold transition " + (form.days.includes(i) ? "bg-blue-500 text-white" : "bg-slate-100 text-slate-600")}>{d}</button>;
          })}
        </div></div>

        <div className="bg-blue-50 border border-blue-200 rounded-lg p-3 text-sm">
          <div className="font-medium text-blue-900 mb-1">Calculations</div>
          <div className="text-blue-800 space-y-0.5">
            <div>{"Concentration: "}<span className="font-semibold">{conc + " " + form.unit + "/ml"}</span></div>
            <div>{"Per dose: "}<span className="font-semibold">{units + " units"}</span>{" on 100u syringe"}</div>
            <div>{"Doses per vial: "}<span className="font-semibold">{total}</span></div>
          </div>
        </div>

        {!isNew && (
          <div className="bg-slate-50 border border-slate-200 rounded-lg p-3">
            <div className="flex items-center gap-2 mb-2"><Package className="w-4 h-4 text-slate-600"/><div className="font-medium text-slate-900 text-sm">Vial tracking</div></div>
            {vialData && vialData.startDate ? (
              <div className="text-sm text-slate-700 mb-2">
                <div>{"Started: " + new Date(vialData.startDate).toLocaleDateString()}</div>
                <div>{"Used: " + (vialData.dosesUsed || 0) + " / " + total}</div>
                <div className={remaining <= 2 ? "text-amber-700 font-semibold" : ""}>{"Remaining: " + remaining + " doses"}</div>
              </div>
            ) : <div className="text-xs text-slate-500 mb-2">No vial started yet</div>}
            <button onClick={onNewVial} className="w-full py-2 bg-white border border-slate-300 rounded-lg text-sm font-medium text-slate-700 mb-2">Start new vial (reset count)</button>
            <label className="text-xs font-medium text-slate-600 block mb-1">Expiry date (optional)</label>
            <input type="date" value={(vialData && vialData.expiryDate) || ""} onChange={function(e){onSetExpiry(e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm"/>
          </div>
        )}

        <div className="flex gap-2">
          {onDelete && <button onClick={onDelete} className="px-4 py-3 bg-red-50 text-red-600 font-semibold rounded-lg hover:bg-red-100 flex items-center"><Trash2 className="w-4 h-4"/></button>}
          <button onClick={handleSave} className="flex-1 py-3 bg-blue-500 text-white font-semibold rounded-lg hover:bg-blue-600 active:scale-[0.98] transition">{isNew ? "Add peptide" : "Save changes"}</button>
        </div>
      </div>
    </Modal>
  );
}

function NutritionTab({nutritionData, setNutritionData}){
  var today = getDateKey(new Date());
  var todayData = nutritionData[today] || {target:2700, mode:"muscle", customMacros:null, entries:[]};

  var [target, setTarget] = useState(todayData.target || 2700);
  var [mode, setMode] = useState(todayData.mode || "muscle");
  var [customMacros, setCustomMacros] = useState(todayData.customMacros || null);
  var [entries, setEntries] = useState(todayData.entries || []);
  var [showAdd, setShowAdd] = useState(false);
  var [addP, setAddP] = useState("");
  var [addC, setAddC] = useState("");
  var [addF, setAddF] = useState("");
  var [addNote, setAddNote] = useState("");

  useEffect(function(){
    var d = nutritionData[today];
    if(d){ setTarget(d.target||2700); setMode(d.mode||"muscle"); setCustomMacros(d.customMacros||null); setEntries(d.entries||[]); }
  },[today]);

  var save = function(t,m,cm,e){
    setNutritionData(function(prev){ return Object.assign({},prev,{[today]:{target:t,mode:m,customMacros:cm,entries:e}}); });
  };

  var preset = MACRO_PRESETS[mode];
  var macroTargets = customMacros || {
    protein: Math.round(target * preset.protein / 100 / 4),
    carbs: Math.round(target * preset.carbs / 100 / 4),
    fat: Math.round(target * preset.fat / 100 / 9)
  };

  var consumed = entries.reduce(function(acc,e){
    return {protein:acc.protein+e.protein, carbs:acc.carbs+e.carbs, fat:acc.fat+e.fat};
  },{protein:0,carbs:0,fat:0});

  var consumedCals = consumed.protein*4 + consumed.carbs*4 + consumed.fat*9;
  var targetCals = customMacros ? (customMacros.protein*4 + customMacros.carbs*4 + customMacros.fat*9) : target;
  var remainingCals = targetCals - consumedCals;

  var addEntry = function(){
    var p=parseFloat(addP)||0, c=parseFloat(addC)||0, f=parseFloat(addF)||0;
    if(p===0&&c===0&&f===0) return;
    var newEntries = entries.concat({protein:p,carbs:c,fat:f,note:addNote,time:new Date().toLocaleTimeString([],{hour:"numeric",minute:"2-digit"})});
    setEntries(newEntries); save(target,mode,customMacros,newEntries);
    setAddP(""); setAddC(""); setAddF(""); setAddNote(""); setShowAdd(false);
  };

  var removeEntry = function(i){ var n=entries.slice(); n.splice(i,1); setEntries(n); save(target,mode,customMacros,n); };
  var resetDay = function(){ if(confirm("Reset today's nutrition?")){ setEntries([]); save(target,mode,customMacros,[]); } };
  var updateTarget = function(v){ var t=parseInt(v)||0; setTarget(t); save(t,mode,customMacros,entries); };
  var updateMode = function(m){ setMode(m); setCustomMacros(null); save(target,m,null,entries); };
  var updateCustomMacro = function(k,v){ var cm=Object.assign({},macroTargets,{[k]:parseInt(v)||0}); setCustomMacros(cm); save(target,mode,cm,entries); };

  var pctP = macroTargets.protein > 0 ? Math.min(100, consumed.protein/macroTargets.protein*100) : 0;
  var pctC = macroTargets.carbs > 0 ? Math.min(100, consumed.carbs/macroTargets.carbs*100) : 0;
  var pctF = macroTargets.fat > 0 ? Math.min(100, consumed.fat/macroTargets.fat*100) : 0;
  var pctCal = targetCals > 0 ? Math.min(100, consumedCals/targetCals*100) : 0;

  function MacroBar({label,current,goal,color,pct}){
    return (
      <div className="mb-3">
        <div className="flex justify-between text-sm mb-1">
          <span className="font-medium text-slate-700">{label}</span>
          <span className={current>goal ? "text-red-600 font-semibold" : "text-slate-600"}>
            {current + "g / " + goal + "g"} <span className="text-xs">{"(" + Math.max(0,goal-current) + "g left)"}</span>
          </span>
        </div>
        <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className={"h-full rounded-full transition-all duration-300 " + (current>goal ? "bg-red-500" : color)} style={{width: pct+"%"}}/>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4">
        <label className="text-sm font-medium text-slate-700 block mb-2">Daily calorie target</label>
        <input type="number" value={target} onChange={function(e){updateTarget(e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg text-lg font-semibold focus:outline-none focus:ring-2 focus:ring-blue-500"/>
        <div className="grid grid-cols-3 gap-2 mt-3">
          {Object.entries(MACRO_PRESETS).map(function(entry){
            var k=entry[0], v=entry[1];
            return <button key={k} onClick={function(){updateMode(k);}} className={"py-2 px-1 rounded-lg text-xs font-semibold transition " + (mode===k && !customMacros ? "bg-blue-500 text-white" : "bg-slate-100 text-slate-600")}>{v.icon + " " + v.name}</button>;
          })}
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4">
        <div className="flex justify-between items-center mb-1">
          <span className="text-sm font-medium text-slate-700">Calories</span>
          <span className={"text-sm font-semibold " + (remainingCals<0 ? "text-red-600" : "text-emerald-600")}>
            {remainingCals > 0 ? remainingCals + " remaining" : Math.abs(remainingCals) + " over"}
          </span>
        </div>
        <div className="flex justify-between text-xs text-slate-500 mb-1">
          <span>{consumedCals + " eaten"}</span><span>{targetCals + " target"}</span>
        </div>
        <div className="h-4 bg-slate-100 rounded-full overflow-hidden mb-4">
          <div className={"h-full rounded-full transition-all duration-300 " + (consumedCals>targetCals ? "bg-red-500" : "bg-blue-500")} style={{width: Math.min(pctCal,100)+"%"}}/>
        </div>

        <div className="text-xs text-slate-500 uppercase tracking-wide mb-2">Macro targets (tap to customize)</div>
        <div className="grid grid-cols-3 gap-2 mb-4">
          <div><label className="text-xs text-slate-500">Protein (g)</label>
          <input type="number" value={macroTargets.protein} onChange={function(e){updateCustomMacro("protein",e.target.value);}} className="w-full px-2 py-1.5 border border-slate-300 rounded-lg text-sm text-center font-semibold"/></div>
          <div><label className="text-xs text-slate-500">Carbs (g)</label>
          <input type="number" value={macroTargets.carbs} onChange={function(e){updateCustomMacro("carbs",e.target.value);}} className="w-full px-2 py-1.5 border border-slate-300 rounded-lg text-sm text-center font-semibold"/></div>
          <div><label className="text-xs text-slate-500">Fat (g)</label>
          <input type="number" value={macroTargets.fat} onChange={function(e){updateCustomMacro("fat",e.target.value);}} className="w-full px-2 py-1.5 border border-slate-300 rounded-lg text-sm text-center font-semibold"/></div>
        </div>

        <MacroBar label="Protein" current={consumed.protein} goal={macroTargets.protein} color="bg-blue-500" pct={pctP}/>
        <MacroBar label="Carbs" current={consumed.carbs} goal={macroTargets.carbs} color="bg-amber-500" pct={pctC}/>
        <MacroBar label="Fat" current={consumed.fat} goal={macroTargets.fat} color="bg-purple-500" pct={pctF}/>
      </div>

      <button onClick={function(){setShowAdd(true);}} className="w-full flex items-center justify-center gap-2 py-3 bg-blue-500 text-white font-semibold rounded-2xl hover:bg-blue-600 active:scale-[0.99] transition">
        <Plus className="w-5 h-5"/>Log food
      </button>

      {entries.length > 0 && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4">
          <div className="text-xs text-slate-500 uppercase tracking-wide mb-2">Today&apos;s log</div>
          <div className="space-y-2">
            {entries.map(function(e,i){
              return (
                <div key={i} className="flex items-center justify-between py-2 px-3 bg-slate-50 rounded-lg">
                  <div className="flex-1">
                    <div className="text-sm font-medium text-slate-900">{e.note || ("Entry " + (i+1))}</div>
                    <div className="text-xs text-slate-500">{"P:" + e.protein + "g \u00b7 C:" + e.carbs + "g \u00b7 F:" + e.fat + "g \u00b7 " + (e.protein*4+e.carbs*4+e.fat*9) + " cal"}</div>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-xs text-slate-400">{e.time}</span>
                    <button onClick={function(){removeEntry(i);}} className="p-1 hover:bg-red-50 rounded"><Trash2 className="w-3.5 h-3.5 text-red-400"/></button>
                  </div>
                </div>
              );
            })}
          </div>
          <button onClick={resetDay} className="w-full flex items-center justify-center gap-2 py-2 mt-3 text-sm text-slate-500 hover:text-slate-700">
            <RotateCcw className="w-3.5 h-3.5"/>Reset today
          </button>
        </div>
      )}

      {showAdd && (
        <Modal onClose={function(){setShowAdd(false);}} title="Log food">
          <div className="space-y-3">
            <div><label className="text-sm font-medium text-slate-700 block mb-1">Meal note (optional)</label>
            <input type="text" value={addNote} onChange={function(e){setAddNote(e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg" placeholder="e.g. Post-workout shake"/></div>
            <div className="grid grid-cols-3 gap-3">
              <div><label className="text-sm font-medium text-slate-700 block mb-1">Protein (g)</label>
              <input type="number" value={addP} onChange={function(e){setAddP(e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg text-center" placeholder="0"/></div>
              <div><label className="text-sm font-medium text-slate-700 block mb-1">Carbs (g)</label>
              <input type="number" value={addC} onChange={function(e){setAddC(e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg text-center" placeholder="0"/></div>
              <div><label className="text-sm font-medium text-slate-700 block mb-1">Fat (g)</label>
              <input type="number" value={addF} onChange={function(e){setAddF(e.target.value);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg text-center" placeholder="0"/></div>
            </div>
            <div className="bg-slate-50 rounded-lg p-2 text-center text-sm text-slate-600">{"= " + ((parseFloat(addP)||0)*4+(parseFloat(addC)||0)*4+(parseFloat(addF)||0)*9) + " calories"}</div>
            <button onClick={addEntry} className="w-full py-3 bg-blue-500 text-white font-semibold rounded-lg hover:bg-blue-600 active:scale-[0.98] transition">Add</button>
          </div>
        </Modal>
      )}
    </div>
  );
}

function HistoryTab({nutritionData, peptides, stackStartDate}){
  var sortedDays = Object.keys(nutritionData).sort(function(a,b){return b.localeCompare(a);});
  var weeksOnStack = stackStartDate ? Math.floor((new Date() - new Date(stackStartDate))/(1000*60*60*24*7)) : 0;

  return (
    <div className="space-y-4">
      {stackStartDate && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4">
          <div className="text-xs text-slate-500 uppercase tracking-wide mb-1">Stack started</div>
          <div className="font-semibold text-slate-900">{new Date(stackStartDate).toLocaleDateString("en-US",{weekday:"long",month:"long",day:"numeric",year:"numeric"})}</div>
          <div className="text-sm text-slate-600 mt-1">{"Week " + (weeksOnStack+1) + " on protocol"}</div>
        </div>
      )}

      {Object.keys(peptides).length > 0 && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4">
          <div className="text-xs text-slate-500 uppercase tracking-wide mb-2">{"Current stack (" + Object.keys(peptides).length + ")"}</div>
          <div className="space-y-1.5">
            {Object.values(peptides).map(function(p){
              return (
                <div key={p.id} className="flex justify-between py-1.5 px-2 bg-slate-50 rounded-lg text-sm">
                  <span className="font-medium text-slate-900">{p.name}</span>
                  <span className="text-slate-500">{p.doseLabel + " \u00b7 " + p.days.map(function(d){return DAY_NAMES[d];}).join(", ")}</span>
                </div>
              );
            })}
          </div>
        </div>
      )}

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4">
        <div className="text-xs text-slate-500 uppercase tracking-wide mb-2">Nutrition log</div>
        {sortedDays.length === 0 ? <div className="text-sm text-slate-400 text-center py-4">No entries yet</div> : (
          <div className="space-y-2">
            {sortedDays.map(function(day){
              var d = nutritionData[day];
              var e = d.entries || [];
              var tot = e.reduce(function(a,x){return {p:a.p+x.protein,c:a.c+x.carbs,f:a.f+x.fat};},{p:0,c:0,f:0});
              var cals = tot.p*4 + tot.c*4 + tot.f*9;
              return (
                <div key={day} className="py-2 px-3 bg-slate-50 rounded-lg">
                  <div className="flex justify-between">
                    <span className="text-sm font-semibold text-slate-900">{new Date(day+"T12:00:00").toLocaleDateString("en-US",{weekday:"short",month:"short",day:"numeric"})}</span>
                    <span className="text-sm font-semibold text-slate-700">{cals + " cal"}</span>
                  </div>
                  <div className="text-xs text-slate-500 mt-0.5">{"P:" + tot.p + "g \u00b7 C:" + tot.c + "g \u00b7 F:" + tot.f + "g \u00b7 " + e.length + " entries"}</div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

function BottomNav({tab, setTab, alerts}){
  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 px-4 py-2 z-40">
      <div className="max-w-md mx-auto flex justify-around">
        <button onClick={function(){setTab("peptides");}} className={"flex flex-col items-center py-1 px-3 rounded-lg transition " + (tab==="peptides" ? "text-blue-600" : "text-slate-400")}>
          <Beaker className="w-5 h-5"/><span className="text-xs mt-0.5 font-medium">Peptides</span>
        </button>
        <button onClick={function(){setTab("nutrition");}} className={"flex flex-col items-center py-1 px-3 rounded-lg transition " + (tab==="nutrition" ? "text-blue-600" : "text-slate-400")}>
          <Apple className="w-5 h-5"/><span className="text-xs mt-0.5 font-medium">Nutrition</span>
        </button>
        <button onClick={function(){setTab("history");}} className={"flex flex-col items-center py-1 px-3 rounded-lg transition " + (tab==="history" ? "text-blue-600" : "text-slate-400")}>
          <Clock className="w-5 h-5"/><span className="text-xs mt-0.5 font-medium">History</span>
        </button>
      </div>
    </div>
  );
}

export default function App(){
  var [tab, setTab] = useState("peptides");
  var [currentDate, setCurrentDate] = useState(new Date());
  var [checked, setChecked] = useState({});
  var [peptides, setPeptides] = useState({});
  var [vialTracking, setVialTracking] = useState({});
  var [stackStartDate, setStackStartDate] = useState(null);
  var [nutritionData, setNutritionData] = useState({});
  var [editingPeptide, setEditingPeptide] = useState(null);
  var [addingNew, setAddingNew] = useState(false);
  var [showPresets, setShowPresets] = useState(false);
  var [showAlerts, setShowAlerts] = useState(false);
  var [showSettings, setShowSettings] = useState(false);
  var [loading, setLoading] = useState(true);

  var dateKey = getDateKey(currentDate);
  var dayIndex = currentDate.getDay();
  var todaysDoses = Object.values(peptides).filter(function(p){return p.days.includes(dayIndex);});
  var dayChecked = checked[dateKey] || {};
  var completedCount = todaysDoses.filter(function(d){return dayChecked[d.id];}).length;
  var allDone = completedCount === todaysDoses.length && todaysDoses.length > 0;
  var isEmpty = Object.keys(peptides).length === 0;

  useEffect(function(){
    var load = async function(){
      try {
        var raw = localStorage.getItem("rico-stack-v1"); var r = raw ? {value: raw} : null;
        if(r){
          var d = JSON.parse(r.value);
          setChecked(d.checked || {});
          setPeptides(d.peptides || {});
          setVialTracking(d.vialTracking || {});
          setStackStartDate(d.stackStartDate || null);
          setNutritionData(d.nutritionData || {});
        }
      } catch(e){}
      setLoading(false);
    };
    load();
  },[]);

  useEffect(function(){
    if(loading) return;
    var save = async function(){
      try {
        localStorage.setItem("rico-stack-v1", JSON.stringify({checked:checked,peptides:peptides,vialTracking:vialTracking,stackStartDate:stackStartDate,nutritionData:nutritionData}));
      } catch(e){ console.error(e); }
    };
    save();
  },[checked, peptides, vialTracking, stackStartDate, nutritionData, loading]);

  var toggleDose = function(id){
    var wasChecked = !!dayChecked[id];
    setChecked(function(prev){
      var day = Object.assign({}, prev[dateKey] || {});
      if(day[id]) delete day[id]; else day[id] = new Date().toISOString();
      return Object.assign({}, prev, {[dateKey]: day});
    });
    setVialTracking(function(prev){
      var t = prev[id]; if(!t) return prev;
      var newUsed = (t.dosesUsed||0) + (wasChecked ? -1 : 1);
      return Object.assign({}, prev, {[id]: Object.assign({}, t, {dosesUsed: Math.max(0, newUsed)})});
    });
    if(!stackStartDate && !wasChecked) setStackStartDate(new Date().toISOString());
  };

  var changeDate = function(delta){ var d = new Date(currentDate); d.setDate(d.getDate()+delta); setCurrentDate(d); };
  var goToday = function(){ setCurrentDate(new Date()); };
  var resetDay = function(){ if(confirm("Reset all checks?")){ setChecked(function(p){ var n=Object.assign({},p); delete n[dateKey]; return n; }); } };
  var savePeptide = function(p){ setPeptides(function(prev){ return Object.assign({},prev,{[p.id]:p}); }); };
  var deletePeptide = function(id){
    if(confirm("Delete " + peptides[id].name + "?")){
      setPeptides(function(p){ var n=Object.assign({},p); delete n[id]; return n; });
      setVialTracking(function(v){ var n=Object.assign({},v); delete n[id]; return n; });
    }
  };
  var startNewVial = function(id){ setVialTracking(function(p){ return Object.assign({},p,{[id]:Object.assign({},p[id]||{},{startDate:new Date().toISOString(),dosesUsed:0})}); }); };
  var setVialExpiry = function(id,d){ setVialTracking(function(p){ return Object.assign({},p,{[id]:Object.assign({},p[id]||{},{expiryDate:d||null})}); }); };
  var addFromPreset = function(preset){
    var id = "p_" + Date.now() + "_" + Math.random().toString(36).slice(2,7);
    savePeptide(Object.assign({},preset,{id:id,doseLabel:preset.doseAmount+preset.unit}));
  };

  var alerts = [];
  Object.values(peptides).forEach(function(p){
    var t = vialTracking[p.id]; if(!t) return;
    var total = dosesPerVial(p); var rem = total - (t.dosesUsed||0);
    if(t.startDate && rem<=2 && rem>=0) alerts.push({peptide:p,type:"doses",remaining:rem});
    if(t.expiryDate){
      var today = new Date(); today.setHours(0,0,0,0);
      var dl = Math.ceil((new Date(t.expiryDate)-today)/86400000);
      if(dl<=7 && dl>=0) alerts.push({peptide:p,type:"date",daysLeft:dl});
    }
  });

  var streak = (function(){
    if(Object.keys(peptides).length===0) return 0;
    var s=0; var t=new Date(); t.setHours(0,0,0,0);
    for(var i=0;i<365;i++){
      var d=new Date(t); d.setDate(d.getDate()-i);
      var dd=Object.values(peptides).filter(function(p){return p.days.includes(d.getDay());});
      if(dd.length===0) continue;
      var dc=checked[getDateKey(d)]||{};
      if(dd.every(function(dose){return dc[dose.id];})) s++;
      else{ if(i===0) continue; break; }
    }
    return s;
  })();

  var weeksOnStack = stackStartDate ? Math.floor((new Date()-new Date(stackStartDate))/(1000*60*60*24*7)) : 0;

  if(loading) return <div className="min-h-screen bg-slate-50 flex items-center justify-center"><div className="text-slate-500">Loading...</div></div>;

  if(isEmpty && tab==="peptides"){
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 p-6 flex flex-col">
        <div className="max-w-md mx-auto w-full flex-1 flex flex-col justify-center">
          <div className="text-center mb-8">
            <img src={LOGO_SRC} alt="RICO" className="w-20 h-20 mx-auto mb-4 rounded-2xl shadow-md"/>
            <h1 className="text-3xl font-bold text-slate-900 mb-2">RICO</h1>
            <p className="text-slate-600">Track your peptides, hormones, and nutrition.</p>
          </div>
          <div className="space-y-3">
            <button onClick={function(){setShowPresets(true);}} className="w-full p-4 bg-white rounded-2xl border-2 border-blue-200 hover:border-blue-400 active:scale-[0.99] transition text-left">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-blue-100 rounded-xl flex items-center justify-center"><Sparkles className="w-5 h-5 text-blue-600"/></div>
                <div><div className="font-semibold text-slate-900">Choose from presets</div><div className="text-sm text-slate-500">Common peptides with defaults</div></div>
              </div>
            </button>
            <button onClick={function(){setAddingNew(true);}} className="w-full p-4 bg-white rounded-2xl border-2 border-slate-200 hover:border-slate-400 active:scale-[0.99] transition text-left">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center"><Plus className="w-5 h-5 text-slate-600"/></div>
                <div><div className="font-semibold text-slate-900">Add custom peptide</div><div className="text-sm text-slate-500">Set everything from scratch</div></div>
              </div>
            </button>
          </div>
          <p className="text-xs text-center text-slate-400 mt-8">Data stored on this device only.</p>
        </div>
        <BottomNav tab={tab} setTab={setTab} alerts={alerts}/>
        {showPresets && <PresetPicker onPick={addFromPreset} onClose={function(){setShowPresets(false);}} existingNames={Object.values(peptides).map(function(p){return p.name.toLowerCase();})}/>}
        {addingNew && <PeptideEditor peptide={null} vialData={null} onSave={function(p){savePeptide(p);setAddingNew(false);}} onClose={function(){setAddingNew(false);}}/>}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <div className="max-w-md mx-auto p-4">
        <div className="mb-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <img src={LOGO_SRC} alt="RICO" className="w-10 h-10 rounded-xl shadow-sm"/>
            <div>
              <h1 className="text-xl font-bold text-slate-900">RICO</h1>
              <p className="text-xs text-slate-500">{stackStartDate ? "Week " + (weeksOnStack+1) + " on protocol" : "Start tracking"}</p>
            </div>
          </div>
          <div className="flex gap-2">
            {tab==="peptides" && (
              <button onClick={function(){setShowAlerts(true);}} className="relative p-2 bg-white border border-slate-200 rounded-lg">
                <AlertTriangle className={"w-4 h-4 " + (alerts.length>0 ? "text-amber-500" : "text-slate-400")}/>
                {alerts.length>0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs rounded-full w-4 h-4 flex items-center justify-center font-bold" style={{fontSize:"10px"}}>{alerts.length}</span>}
              </button>
            )}
            <button onClick={function(){setShowSettings(true);}} className="p-2 bg-white border border-slate-200 rounded-lg">
              <Settings className="w-4 h-4 text-slate-600"/>
            </button>
          </div>
        </div>

        {tab==="peptides" && (
          <div>
            {alerts.length>0 && (
              <div className="bg-amber-50 border-2 border-amber-300 rounded-2xl p-3 mb-4 flex items-start gap-2">
                <AlertTriangle className="w-5 h-5 text-amber-600 flex-shrink-0 mt-0.5"/>
                <div className="text-sm text-amber-900"><span className="font-semibold">{alerts.length + " vial alert" + (alerts.length!==1?"s":"")}</span></div>
              </div>
            )}

            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-3 mb-4 flex items-center justify-between">
              <button onClick={function(){changeDate(-1);}} className="p-2 hover:bg-slate-100 rounded-lg"><ChevronLeft className="w-5 h-5 text-slate-600"/></button>
              <button onClick={goToday} className="text-center flex-1">
                <div className="font-semibold text-slate-900">{formatDate(currentDate)}</div>
                {getDateKey(new Date())!==dateKey && <div className="text-xs text-blue-600 mt-0.5">Tap for today</div>}
              </button>
              <button onClick={function(){changeDate(1);}} className="p-2 hover:bg-slate-100 rounded-lg"><ChevronRight className="w-5 h-5 text-slate-600"/></button>
            </div>

            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 mb-4">
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm font-medium text-slate-700">{completedCount + " of " + todaysDoses.length + " done"}</span>
                {streak>0 && <span className="text-xs font-medium text-emerald-700 bg-emerald-50 px-2 py-1 rounded-full flex items-center gap-1"><TrendingUp className="w-3 h-3"/>{streak + "d"}</span>}
              </div>
              <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
                <div className={"h-full transition-all duration-300 " + (allDone ? "bg-emerald-500" : "bg-blue-500")} style={{width: (todaysDoses.length ? (completedCount/todaysDoses.length)*100 : 0)+"%"}}/>
              </div>
              {allDone && <div className="text-xs text-emerald-700 mt-2 font-medium">All doses complete \u2713</div>}
              {todaysDoses.length===0 && <div className="text-xs text-slate-500 mt-2">No doses scheduled today</div>}
            </div>

            <div className="space-y-2 mb-4">
              {todaysDoses.map(function(p){
                var isC = !!dayChecked[p.id];
                var u = calcUnits(p.doseAmount, p);
                var t = vialTracking[p.id];
                var total = dosesPerVial(p);
                var rem = t ? total-(t.dosesUsed||0) : null;
                var low = rem!==null && rem<=2 && rem>=0;
                return (
                  <div key={p.id} className={"rounded-2xl border-2 transition-all overflow-hidden " + (isC ? "bg-emerald-50 border-emerald-300" : low ? "bg-white border-amber-300" : "bg-white border-slate-200")}>
                    <button onClick={function(){toggleDose(p.id);}} className="w-full flex items-center gap-3 p-4 active:scale-[0.99] transition">
                      <div className={"w-6 h-6 rounded-full border-2 flex items-center justify-center flex-shrink-0 " + (isC ? "bg-emerald-500 border-emerald-500" : "border-slate-300")}>
                        {isC && <Check className="w-4 h-4 text-white" strokeWidth={3}/>}
                      </div>
                      <div className="flex-1 text-left">
                        <div className="flex items-center gap-2">
                          <div className={"w-2 h-2 rounded-full " + (categoryDot[p.category]||"bg-slate-400")}/>
                          <div className={"font-semibold " + (isC ? "text-emerald-900 line-through opacity-70" : "text-slate-900")}>{p.name}</div>
                          {low && <span className="text-xs bg-amber-100 text-amber-800 px-1.5 py-0.5 rounded font-medium">{rem + " left"}</span>}
                        </div>
                        <div className={"text-sm " + (isC ? "text-emerald-700 opacity-70" : "text-slate-500")}>
                          {p.doseLabel}<span className="ml-2 font-medium text-blue-600">{"\u2192 " + u.toFixed(1) + " units"}</span>
                        </div>
                      </div>
                      {isC && dayChecked[p.id] && <div className="text-xs text-emerald-600">{new Date(dayChecked[p.id]).toLocaleTimeString([],{hour:"numeric",minute:"2-digit"})}</div>}
                    </button>
                    <button onClick={function(e){e.stopPropagation();setEditingPeptide(p.id);}} className="w-full px-4 py-2 text-xs text-slate-500 hover:bg-slate-50 border-t border-slate-100 flex items-center justify-center gap-1">
                      <Beaker className="w-3 h-3"/>{p.vialMg + p.unit + " / " + p.bacMl + "ml BAC \u00b7 edit"}
                    </button>
                  </div>
                );
              })}
            </div>

            <div className="grid grid-cols-2 gap-2 mb-4">
              <button onClick={function(){setShowPresets(true);}} className="flex items-center justify-center gap-2 py-3 bg-white border-2 border-dashed border-slate-300 rounded-2xl text-slate-600 font-medium text-sm"><Sparkles className="w-4 h-4"/>Presets</button>
              <button onClick={function(){setAddingNew(true);}} className="flex items-center justify-center gap-2 py-3 bg-white border-2 border-dashed border-slate-300 rounded-2xl text-slate-600 font-medium text-sm"><Plus className="w-4 h-4"/>Custom</button>
            </div>

            {completedCount>0 && <button onClick={resetDay} className="w-full flex items-center justify-center gap-2 py-3 text-sm text-slate-500"><RotateCcw className="w-4 h-4"/>Reset day</button>}
          </div>
        )}

        {tab==="nutrition" && <NutritionTab nutritionData={nutritionData} setNutritionData={setNutritionData}/>}
        {tab==="history" && <HistoryTab nutritionData={nutritionData} peptides={peptides} stackStartDate={stackStartDate}/>}
      </div>

      <BottomNav tab={tab} setTab={setTab} alerts={alerts}/>

      {(editingPeptide || addingNew) && (
        <PeptideEditor
          peptide={editingPeptide ? peptides[editingPeptide] : null}
          vialData={editingPeptide ? vialTracking[editingPeptide] : null}
          onSave={function(p){savePeptide(p);setEditingPeptide(null);setAddingNew(false);}}
          onClose={function(){setEditingPeptide(null);setAddingNew(false);}}
          onDelete={editingPeptide ? function(){deletePeptide(editingPeptide);setEditingPeptide(null);} : null}
          onNewVial={editingPeptide ? function(){startNewVial(editingPeptide);} : null}
          onSetExpiry={editingPeptide ? function(d){setVialExpiry(editingPeptide,d);} : null}
        />
      )}

      {showPresets && <PresetPicker onPick={addFromPreset} onClose={function(){setShowPresets(false);}} existingNames={Object.values(peptides).map(function(p){return p.name.toLowerCase();})}/>}

      {showAlerts && (
        <Modal onClose={function(){setShowAlerts(false);}} title="Vial Alerts">
          {alerts.length===0 ? <div className="text-sm text-slate-500 text-center py-6">No active alerts.</div> : (
            <div className="space-y-3">
              {alerts.map(function(a,i){
                return (
                  <div key={i} className="bg-amber-50 border border-amber-200 rounded-lg p-3">
                    <div className="font-semibold text-amber-900">{a.peptide.name}</div>
                    <div className="text-sm text-amber-800 mt-1">{a.type==="doses" ? a.remaining + " dose" + (a.remaining!==1?"s":"") + " left" : "Expires in " + a.daysLeft + " day" + (a.daysLeft!==1?"s":"")}</div>
                  </div>
                );
              })}
            </div>
          )}
        </Modal>
      )}

      {showSettings && (
        <Modal onClose={function(){setShowSettings(false);}} title="Settings">
          <div className="space-y-4">
            <div className="bg-slate-50 rounded-lg p-3">
              <div className="text-xs text-slate-500 uppercase tracking-wide mb-1">Stack start date</div>
              <input type="date" value={stackStartDate ? stackStartDate.slice(0,10) : ""} onChange={function(e){setStackStartDate(e.target.value ? new Date(e.target.value).toISOString() : null);}} className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm"/>
            </div>
            <button onClick={function(){
              if(confirm("Delete ALL data?") && confirm("Really sure?")){
                setPeptides({}); setChecked({}); setVialTracking({}); setStackStartDate(null); setNutritionData({}); setShowSettings(false);
              }
            }} className="w-full py-3 bg-red-50 text-red-600 font-semibold rounded-lg flex items-center justify-center gap-2">
              <Trash2 className="w-4 h-4"/>Reset all data
            </button>
          </div>
        </Modal>
      )}
    </div>
  );
}
